// Parse CSV text returned by ScraperCity download endpoint
// Expected columns: name, website, email, phone, instagram, facebook, country

const csvText = items[0].json.data || items[0].json.body || '';

if (!csvText || csvText.trim().length === 0) {
  return [];
}

const lines = csvText.trim().split('\n');
if (lines.length < 2) return [];

// Parse header row - handle quoted headers
const parseCSVLine = (line) => {
  const result = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') {
      inQuotes = !inQuotes;
    } else if (ch === ',' && !inQuotes) {
      result.push(current.trim());
      current = '';
    } else {
      current += ch;
    }
  }
  result.push(current.trim());
  return result;
};

const headers = parseCSVLine(lines[0]).map(h => h.toLowerCase().replace(/\s+/g, '_'));

const seen = new Set();
const output = [];

for (let i = 1; i < lines.length; i++) {
  if (!lines[i].trim()) continue;
  const values = parseCSVLine(lines[i]);
  const record = {};
  headers.forEach((h, idx) => {
    record[h] = values[idx] || '';
  });

  // Normalize email
  const email = (record.email || '').trim().toLowerCase();

  // Deduplicate by email; allow blank emails but only one blank
  const dedupeKey = email || ('no-email-' + i);
  if (seen.has(dedupeKey)) continue;
  seen.add(dedupeKey);

  output.push({ json: record });
}

return output;
